#include <stdio.h>
#include <string.h>

int main() {
    int n;
    char you[10], computer[10], choice[10];
    int youScore = 0, computerScore = 0;

    scanf("%d", &n);
    getchar();

    for (int i = 0; i < n; i++) {
        fgets(you, sizeof(you), stdin);
        sscanf(you, "%s %s", you, choice);
        fgets(computer, sizeof(computer), stdin);
        if (strcmp(you, "You") == 0) {
            if (strcmp(choice, "Rock") == 0) {
                if (strcmp(computer, "Scissors") == 0 || strcmp(computer, "Water") == 0) {
                    youScore++;
                }
            } else if (strcmp(choice, "Paper") == 0) {
                if (strcmp(computer, "Rock") == 0 || strcmp(computer, "Scissors") == 0 || strcmp(computer, "Water") == 0) {
                    youScore++;
                }
            } else if (strcmp(choice, "Scissors") == 0) {
                if (strcmp(computer, "Paper") == 0 || strcmp(computer, "Water") == 0) {
                    youScore++;
                }
            } else if (strcmp(choice, "Water") == 0) {
                if (strcmp(computer, "Paper") == 0 || strcmp(computer, "Scissors") == 0) {
                    youScore++;
                }
            }
        } else {
            if (strcmp(choice, "Rock") == 0) {
                if (strcmp(you, "Scissors") == 0 || strcmp(you, "Water") == 0) {
                    computerScore++;
                }
            } else if (strcmp(choice, "Paper") == 0) {
                if (strcmp(you, "Rock") == 0 || strcmp(you, "Scissors") == 0 || strcmp(you, "Water") == 0) {
                    computerScore++;
                }
            } else if (strcmp(choice, "Scissors") == 0) {
                if (strcmp(you, "Paper") == 0 || strcmp(you, "Water") == 0) {
                    computerScore++;
                }
            } else if (strcmp(choice, "Water") == 0) {
                if (strcmp(you, "Paper") == 0 || strcmp(you, "Scissors") == 0) {
                    computerScore++;
                }
            }
        }
        printf("Round %d: %s\n", i + 1, (strcmp(you, "You") == 0) ? "You" : "Computer");
    }

    printf("%s won the overall match\n", (youScore > computerScore) ? "You" : "Computer");

    return 0;
}

